import './ScoresheetTab.css';
import {useState} from "react";
import {useEffect} from "react";
import {MatchSorter} from "./TimingTab";
import {useLocalStorageState} from "first-common/utils";
import { HrBasicMatch } from './HeadRef';
import {t} from "ftc-common/i18n";


export default function ScoresheetTab({matchLists, divisionNames}: {
    matchLists: Record<number, HrBasicMatch[]>,
    divisionNames?: string[]
}) {
    const [activeDivision, setActiveDivision] = useState(window.division);
    const [match, setMatch] = useState<string | null>(null);
    const [sheet, setSheet] = useState('both');
    const [sheetData, setSheetData] = useState<string | null>(null);
    const [playoffOnly, setPlayoffOnly] = useLocalStorageState("hr-scoresheet-playoff-only", false);

    useEffect(() => {
        (async () => {
            if (!match || !sheet) {
                setSheetData(null);
                return;
            }
            let eventCode = window.eventCode;
            if(eventCode.endsWith("_0")) {
                eventCode = eventCode.slice(0, -2) + "_" + activeDivision;
            }
            const url = `/event/${eventCode}/match/${match.toLowerCase()}/${sheet !== 'both' ? sheet + "/" : ""}?embed=true`;
            const response = await fetch(url);
            const html = await response.text();
            setSheetData(html);
        })()
    }, [activeDivision, match, sheet]);

    const NAMES = {red: t`Red`, blue: t`Blue`, both: t`Both`}
    const matchList = matchLists[activeDivision] || [];
    const opts = matchList.filter(x => playoffOnly ? x.type === "ELIMS" : true).toSorted(MatchSorter).map(m => <option value={m.shortName} key={m.shortName}>{m.shortName}</option> )
    const btns = (['red', 'blue', 'both'] as const).map(x => <div className={"form-check-inline"} key={x}>
        <input className={"form-check-input"} type={"radio"} name={"scoresheetOption"} id={"scoresheetRadio_" + x} value={x} checked={x === sheet} onChange={(e) => {
            if(e.target.checked) { setSheet(x) }
        }}/>
        <label className="form-check-label" htmlFor={"scoresheetRadio_" + x}>{NAMES[x]}</label>
    </div> );
    return <>
        <div className={"text-center"} style={{marginTop: "10px"}}>
            {divisionNames ? <>
                <label style={{marginRight: '10px'}}>{t`Division: `}</label>
                <select value={activeDivision} onChange={(e) => {
                    setActiveDivision(parseInt(e.target.value))
                    setMatch(null)
                }} className={"mr-4"}>
                    {divisionNames.map((name, index) => <option value={index} key={index}>{name || "Parent"}</option>)}
                </select>
            </>: null}
            <label style={{marginRight: '10px'}}>{t`Match: `}</label>
            <select value={match || '-placeholder-'} onChange={(e) => setMatch(e.target.value)}>
                <option value="-placeholder-" disabled>{t`Select Match`}</option>
                {opts}
            </select>
            <div className={"form-check-inline ml-4"}>
                <label className="form-check-label mr-1" htmlFor={"scoresheetPlayoffOnly"}>{t`Playoff Only: `}</label>
                <input className={"form-check-input"} type={"checkbox"} name={"scoresheetOption"} id={"scoresheetPlayoffOnly"} checked={playoffOnly} onChange={(e) => {
                    setPlayoffOnly(e.target.checked)
                }}/>
            </div>
        </div>
        <div className={"text-center"}>
            {btns}
        </div>
        {sheetData ? <div className="scoresheetContainer" dangerouslySetInnerHTML={{ __html: sheetData }}/> : null}
    </>

}