import {Button, Modal, Form} from "react-bootstrap";
import { t } from "ftc-common/i18n";
import { HrBasicMatch } from "./HeadRef";
import { HRMatchNote, HRMatchNoteItem } from "../javaTypes";


function NoteItem({item, index, match, updateItem}: {
    item: HRMatchNoteItem,
    index: number,
    match: HrBasicMatch | undefined,
    updateItem: (i: number, changes: HRMatchNoteItem) => void
}) {

    const update = (changes: Partial<HRMatchNoteItem>) => updateItem(index, Object.assign({tags: []}, item, changes));
    let tagBoxes;
    if (match) {
        tagBoxes = (["red", "blue"] as const).map(a =>
            <Form className={'d-flex justify-content-between'} style={{marginRight: '1em', padding: '0 5px 0 5px', backgroundColor: a === 'red' ? '#FFB2B2' : '#B2D7FF'}} key={a}> {
                match?.[a].map(team => team && team.number > 0 ? <div className={'d-flex tagItem'} key={team.number}>
                    <Form.Check id={`tag${index}${team.number}`} checked={item.tags?.includes(team.number)} onChange={(e) => update({tags: e.target.checked ? [...item.tags, team.number] : item.tags.filter(x => x !== team.number)})} label={team.displayNumber}/>
                </div> : null)
            } </Form>);
    } else {
        tagBoxes = <Form className={'d-flex justify-content-between'} style={{marginRight: '1em', padding: '0 5px 0 5px'}}> {
            item.tags.map(team => team && team > 0 ? <div className={'d-flex tagItem'} key={team}>
                <Form.Check id={`tag${index}${team}`} checked={true} disabled={true} label={team}/>
            </div> : null)
        } </Form>;
    }


    return <Form.Group>
        <Form.Label className={"drop"}>{t`Detail:`}</Form.Label>
        <Form.Control type={"text"} disabled={!match} value={item?.content || ''} onChange={(e) => update({'content': e.target.value})}/>
        <div className={"d-flex justify-content-left flex-wrap"} style={{marginTop: '.2em'}}>
            <span style={{marginRight: '1em'}}>{t`Tags:`}</span>
            {tagBoxes}
        </div>
    </Form.Group>
}

export default function NoteDialog({show, setShow, match, note, setNote, send}: {
    show: boolean,
    setShow: (show: boolean) => void,
    match: HrBasicMatch | undefined,
    note: HRMatchNote | undefined,
    setNote: (note: HRMatchNote) => void,
    send: (message: string) => void
}) {
    if (!note) {
        return null;
    }
    const updateItem = (i: number, changes: HRMatchNoteItem) => {
        if (!match) {
            return;
        }
        let newNote = Object.assign({}, note);
        if (!newNote.items) {
            newNote.items = [];
        }
        newNote.items[i] = Object.assign({}, changes);
        setNote(newNote);
    }

    const items = note.items?.map((item, i) => <NoteItem item={item} index={i} match={match} key={i} updateItem={updateItem}/>) || [];
    if (match) {
        const next = note.items?.length ?? 0;
        items.push(<NoteItem index={next} match={match} key={next} updateItem={updateItem} item={{content: '', tags: []}}/>);
    }
    let summary;
    let footer;
    if (match) {
        const redTeams = match?.red.filter(x => x && x.number > 0).map(x => x.displayNumber).join(", ");
        const blueTeams = match?.blue.filter(x => x && x.number > 0).map(x => x.displayNumber).join(", ");
        summary = <>
            <Form.Label>{t`Red: ${redTeams} `}</Form.Label>
            <br/>
            <Form.Label>{t`Blue: ${blueTeams} `}</Form.Label>
            <br/>
        </>;
        footer = <>
            <Button variant={"secondary"} onClick={() => setShow(false)}>{t`Cancel`}</Button>
            <Button variant={"primary"} onClick={() => {
                send(JSON.stringify({type: 'NOTE', note: note}));
                setShow(false);
            }}>{t`Save`}</Button>
        </>;
    } else {
        summary = <Form.Label>This note is from a match that is not part of the current event's match schedule and is read-only.</Form.Label>;
        footer = <Button variant={"secondary"} onClick={() => setShow(false)}>{t`Done`}</Button>;
    }
    return <Modal show={show} onHide={() => setShow(false)} size="lg" className="noteModal">
        <Modal.Header closeButton>
            <Modal.Title>{t`Match Note`}</Modal.Title>
        </Modal.Header>
        <Modal.Body>
            <Form.Label>{t`Match: ${note.match}`}</Form.Label><br/>
            {summary}
            <Form.Label className={"drop"}>{t`General/Summary:`}</Form.Label>
            <Form.Control type={"text"} value={note.summary || ''} disabled={!match} onChange={(e) => match ? setNote(Object.assign({}, note, {'summary': e.target.value})) : null}/>
            {items}
        </Modal.Body>
        <Modal.Footer>
            {footer}
        </Modal.Footer>
    </Modal>
}