import {useEffect, useState} from "react";
import {Button, Modal, Form} from "react-bootstrap";
import { HRMatchNote } from "../javaTypes";
import { t } from "ftc-common/i18n";
import { HrBasicMatch, ShowNote, TeamNote } from "./HeadRef";

export default function TeamNotesDialog({show, setShow, notes, noteList, matchList, showNote, send}: {
    show: boolean,
    setShow: (show: boolean) => void,
    notes?: {team: {number: number, displayNumber: string, cards?: string[]}, notes: TeamNote[]},
    noteList: Record<string, HRMatchNote>,
    showNote: ShowNote,
    matchList: HrBasicMatch[],
    // TODO: eventually type this
    send: (message: string) => void,
}) {
    function getGeneralNote(noteList: Record<string, HRMatchNote>, team?: number) {
        if(!team) return "";
        return noteList.G?.items.find(x => x.tags.includes(team))?.content ?? "";
    }

    const [initialGeneral, setInitialGeneral] = useState(getGeneralNote(noteList));
    const [general, setGeneral] = useState(initialGeneral);

    useEffect(() => {
        const init = getGeneralNote(noteList, notes?.team?.number);
        setGeneral(init);
        setInitialGeneral(init)
    }, [notes]); //clear the input on change of team (notes.team)

    if(!notes) {
        return null
    }

    const fullMatchList: (HrBasicMatch | { shortName: string, fake: true })[] = [...matchList];
    for (const matchNoteIndex in notes.notes) {
        const matchNote = notes.notes[matchNoteIndex];
        if (matchNote.match === 'G') {
            continue;
        }
        if (fullMatchList.filter(x => matchNote.match === x.shortName).length === 0) {
            // We don't have the match that this note belongs to - fake it
            fullMatchList.splice(0, 0, {'shortName': matchNote.match, 'fake': true})
        }
    }

    const rows = fullMatchList.map(match => <tr key={match.shortName} style={{border: '1px solid gray', width: '100%'}} onClick={() => match.hasOwnProperty('fake') ? null : showNote(noteList?.[match.shortName] ?? {match: match.shortName, items: []})}>
        <th className="h6 align-top" style={{maxWidth: '7ch', padding: '5px 10px 10px 0'}}>{match.hasOwnProperty('fake') ? match.shortName + ":" : <a href={'#'} onClick={e => e.preventDefault()}>{match.shortName + ":"}</a>}</th>
        <td style={{fontSize: '1.2em'}}> {
            notes.notes.filter(x => x.match === match.shortName)
                .map((item, idx) => <div key={idx}>{item.content}{item.others.length > 0 ? <> [+{item.others.map((t,i) => <>{i > 0 ? ', ' : null}<a href={'#'} key={t} onClick={(e) => { e.preventDefault(); showNote(noteList, 'team', { number: t, displayNumber: t.toString() }) }}>{t}</a></>)}] </> : null}</div>)
        } </td>
    </tr>);

    const displayNumber = notes.team?.displayNumber;
    const cardList = notes.team?.cards?.join(', ')

    return <Modal show={show} onHide={() => setShow(false)} size="lg" className="noteModal">
        <Modal.Header closeButton>
            <Modal.Title>{t`Team ${displayNumber} Match Notes`}</Modal.Title>
        </Modal.Header>
        <Modal.Body>
            {cardList ? <div className="alert alert-warning">{t`This team has received cards in matches: ${cardList}`}</div> : null}
            <Form.Label className={"drop"}>{t`General/Summary:`}</Form.Label>
            <Form.Control type={"text"} value={general} onChange={(e) => setGeneral((e.target as HTMLInputElement).value)}/>
            <br/>
            <table style={{borderCollapse: 'collapse', width: '100%'}}>
                {rows}
            </table>
        </Modal.Body>
        <Modal.Footer>
            <Button variant={"secondary"} hidden={initialGeneral === general} onClick={() => setShow(false)}>{t`Cancel`}</Button>
            <Button variant={"primary"} hidden={initialGeneral === general} onClick={() => {
                const generalNote = noteList.G ?? {match: 'G', items: []};
                const item = generalNote.items.find(x => x.tags.includes(notes.team.number));
                if (!item) {
                    generalNote.items.push({content: general, tags: [notes.team.number]});
                } else {
                    item.content = general;
                }
                send(JSON.stringify({type: 'NOTE', note: generalNote}))
                setShow(false);
            }}>{t`Save`}</Button>
            <Button variant={"secondary"} hidden={initialGeneral !== general} onClick={() => setShow(false)}>{t`Close`}</Button>
        </Modal.Footer>
    </Modal>
}
