const Check = ({value}: {value: number | undefined}) => <i className={`${value === 2 ? "far" : "fa"} fa-fw fa-${value === undefined ? 'minus' : (value > 0 ? (value === 2 ? "check-square" : "check") : "times")}`}/>;

const RobotLocation = ({value}: {value: number}) => value === 1 ? "Partial" : (value > 1 ? "Full" : <i className="fa fa-times fa-fw"/>);
const Positive = ({value}: {value: number}) => <>{Math.max(value, 0)}</>;
const Identity = ({value}: {value: any}) => <>{value}</>;

function CardRowTeam({flip, alliance, team, noShow, card, carry, updateCard, showCard, noteCount, showNote}: {
    flip: boolean,
    alliance: 'red' | 'blue',
    team?: string,
    noShow: number,
    card: number,
    carry: string[],
    updateCard: (a: AllianceColor) => void,
    showCard: boolean,
    noteCount: number,
    showNote: () => void
}) {
    const COLORS = ["white", "yellow", "red", "linear-gradient(to bottom right, yellow 0%,yellow 50%,red 50%,red 50%)"];
    const TEXT = [t`None`, t`YC`, t`RC`, t`2nd YC`];

    const teamDiv = <div className={`col-3 text-center ${alliance} team ${carry?.length ? "carries" : null} ${noShow ? "noshow" : null}`} onClick={() => showNote()}>
        {team}{noteCount > 0 ? <span className={"ml-2 position-relative"}><i className={"fa fa-comment"}></i><span className={"refNoteCount"}>{noteCount}</span></span> : null }
    </div>;
    let cardDiv = <div className={`col-3 text-center ${alliance} card`} onClick={() => updateCard(alliance.toUpperCase() as AllianceColor)} style={{background: COLORS[card]}}>{TEXT[card]}</div>
    if (!showCard) {
        cardDiv = <div className={`col-3 text-center ${alliance}`}/>
    }
    return <>
        {flip ? cardDiv : teamDiv}
        {flip ? teamDiv : cardDiv}
    </>
}

function getUpdateObj(activeMatch: HrMatch) {
    return {
        type: "UPDATE",
        match: activeMatch.number,
        review: activeMatch.hrReview,
        hrCards: activeMatch.hrCards,
        hrViolations: activeMatch.hrViolations,
        redMinor: activeMatch.red.scores.hrMinorFouls,
        redMajor: activeMatch.red.scores.hrMajorFouls,
        blueMinor: activeMatch.blue.scores.hrMinorFouls,
        blueMajor: activeMatch.blue.scores.hrMajorFouls,
    }
}

enum Card {
    NO_CARD = 0,
    YELLOW_CARD = 1,
    RED_CARD = 2,
    YELLOW_RED_CARD = 3
}

const NEXT_CARD = {
    [Card.NO_CARD]: Card.YELLOW_CARD,
    [Card.YELLOW_CARD]: Card.YELLOW_RED_CARD,
    [Card.YELLOW_RED_CARD]: Card.RED_CARD,
    [Card.RED_CARD]: Card.NO_CARD
};

interface InitialCards { RED: number[], BLUE: number[] }

function CardRow({activeMatch, flip, robot, send, showCard, notes, showNote, initialCards}: {
    activeMatch: HrMatch,
    flip: boolean,
    robot: 1 | 2 | 3,
    // TODO add proper typing
    send: (message: string) => void,
    showCard: boolean,
    notes: Map<number, TeamNote[]>,
    showNote: (team: number, displayNumber: string, cards: string[]) => void,
    initialCards?: InitialCards
}) {
    const allianceCards = activeMatch.type === "ELIMS";
    const red = activeMatch.red[`team${robot}`]?.data?.displayNumber;
    const redNumber = activeMatch.red[`team${robot}`]?.data?.number;
    const blue = activeMatch.blue[`team${robot}`]?.data?.displayNumber;
    const blueNumber = activeMatch.blue[`team${robot}`]?.data?.number;
    const redCarry = activeMatch.redData?.[`cc${allianceCards || robot == 3 ? 1 : robot}`];
    const blueCarry = activeMatch.blueData?.[`cc${allianceCards || robot == 3 ? 1 : robot}`];
    const redCard = activeMatch.hrCards['RED'][allianceCards || robot == 3 ? 0 : robot - 1] as Card;
    const blueCard = activeMatch.hrCards['BLUE'][allianceCards || robot == 3 ? 0 : robot - 1] as Card;
    const redNoShow = activeMatch.red.scores[`noshow${robot}`];
    const blueNoShow = activeMatch.blue.scores[`noshow${robot}`];
    const redHasNotes = redNumber ? notes.get(redNumber)?.length || 0 : 0;
    const blueHasNotes = blueNumber ? notes.get(blueNumber)?.length || 0 : 0;
    const updateCard = (a: 'RED' | 'BLUE') => {
        const current = a === 'RED' ? redCard : blueCard;
        const hasCarry = a === 'RED' ? redCarry?.length : blueCarry?.length;

        let n = NEXT_CARD[current];
        if (n == Card.YELLOW_CARD && hasCarry) {
            // if we are not a replay, force to 2nd YC, if it is a replay, force it only if the team that carries did
            // not earn on in the original play. This allows discretionary removal of the card for a team whose carry is the original match
            if (!activeMatch.isReplay || (initialCards && initialCards[a][robot - 1] == 0)) {
                n = NEXT_CARD[n];
            }
        }
        const obj = getUpdateObj(activeMatch);
        obj.review = true;
        if (allianceCards) {
            obj.hrCards[a].fill(n, 0, 3);
        } else {
            obj.hrCards[a][robot - 1] = n;
        }
        send(JSON.stringify(obj));
        // should we fake a SCORE object to the activeMatchState reducer to update the match state in case of latency?
    }

    const redTeam = <CardRowTeam flip={!flip} alliance={'red'} team={red} noShow={redNoShow} card={redCard} carry={redCarry} updateCard={updateCard} showCard={showCard} noteCount={redHasNotes} showNote={() => redNumber && red && showNote(redNumber, red, redCarry)}/>
    const blueTeam = <CardRowTeam flip={flip} alliance={'blue'} team={blue} noShow={blueNoShow} card={blueCard} carry={blueCarry} updateCard={updateCard} showCard={showCard} noteCount={blueHasNotes} showNote={() => blueNumber && blue && showNote(blueNumber, blue, blueCarry)}/>

    if (!red && !blue && robot === 3) {
        return null;
    }
    return  <div className="row cardRow">
        {flip ? redTeam : blueTeam}
        {flip ? blueTeam : redTeam}
    </div>
}

function AllianceRpInputs({activeMatch, alliance, send} : {
    activeMatch: HrMatch,
    alliance: AllianceColor,
    send: (message: string) => void
}) {

    const update = (checked: boolean, v: string) => {
        const obj = getUpdateObj(activeMatch);
        obj.review = true;
        if (checked) {
            obj.hrViolations[alliance].push(v);
        } else {
            obj.hrViolations[alliance] = obj.hrViolations[alliance].filter(x => x !== v);
        }
        send(JSON.stringify(obj));
    }

    return <div className={"rpInputBlock"} style={{maxWidth: 'calc(min(40%, 28ch))'}}>
        {["G206", "G417.A", "G418.A", "G418.B", "G419.B", "G431.C"].map(v => <Form.Check
           key={v} label={v} checked={activeMatch.hrViolations[alliance].includes(v)} id={alliance + "_" + v}
           onChange={e => update(e.target.checked, v)} inline={true}
           style={{minWidth: '5.5em'}}
        />)}
    </div>

}

type ScoreField = keyof SeasonScores
function ScoreRow<T extends ScoreField>({activeMatch, flip, id, fieldName, label, component: Component = Identity, classFn}: {
    activeMatch: HrMatch,
    flip: boolean,
    id?: string,
    label: ReactNode,
} & ({
    fieldName: T | T[] | Record<AllianceColor, T | T[]>,
    component?: ComponentType<{ value: SeasonScores[T], alliance: AllianceColor }>,
    classFn?: (red: SeasonScores[T] | SeasonScores[T][], blue: SeasonScores[T] | SeasonScores[T][]) => {red?: string, middle?: string, blue?: string}
} | {
    fieldName?: undefined,
    component?: ComponentType<{ alliance: AllianceColor }>,
    classFn?: () => {red?: string, middle?: string, blue?: string}
})) {
    const render = (scores: SeasonScores, a: AllianceColor) => {
        const realFieldName = typeof fieldName === 'object' && !Array.isArray(fieldName) ? fieldName[a] : fieldName;
        if (Array.isArray(realFieldName)) {
            return realFieldName.flatMap((x, idx) => [' / ',
                <Component key={`${idx}-body`} value={scores[x]} alliance={a}/>]).slice(1);
        } else if (realFieldName) {
            return <Component value={scores[realFieldName]} alliance={a}/>;
        } else {
            const ValuelessComponent = Component as ComponentType<{ alliance: AllianceColor }>;
            return <ValuelessComponent alliance={a}/>;
        }
    };
    const extractRaw = (scores: SeasonScores, a: AllianceColor) => {
        const realFieldName = typeof fieldName === 'object' && !Array.isArray(fieldName) ? fieldName[a] : fieldName;
        return (Array.isArray(realFieldName) ? realFieldName.map(x => scores[x]) : scores[realFieldName!]);
    }

    const red = render(activeMatch.red.scores, AllianceColor.RED);
    const blue = render(activeMatch.blue.scores, AllianceColor.BLUE);
    const classes = classFn ? (fieldName ? classFn(extractRaw(activeMatch.red.scores, AllianceColor.RED), extractRaw(activeMatch.blue.scores, AllianceColor.BLUE)) : (classFn as () => {red?: string, middle?: string, blue?: string})()) : null;
    return <div className="row scoreRow" id={id}>
        <div className={`col-4 d-flex justify-content-center align-items-center ${flip ? "red" : "blue"} ${flip ? classes?.red : classes?.blue} p-0`}>{flip ? red : blue}</div>
        <div className={`col-4 text-center middle ${classes?.middle}`}>{label}</div>
        <div className={`col-4 d-flex justify-content-center align-items-center ${flip ? "blue" : "red"} ${flip ? classes?.blue : classes?.red} p-0`}>{flip ? blue : red}</div>
    </div>;
}

function getLagStatus(ref: RefStatus, timer: MatchTimerData, matchState: MatchState, waitForInitSubmit: boolean) {
    if (matchState === "UNPLAYED" || matchState == "RANDOMIZED") {
        if (ref === "READY") {
            return "ready"
        }
        if (matchState === "RANDOMIZED") {
            return waitForInitSubmit ? "blocking" : "conflict"
        }
        return waitForInitSubmit ? "blocking" : undefined;
    } else {
        if (timer.done) {
            return ref === "SUBMIT" ? "ready" : (ref === "REVIEW" ? undefined : "conflict");
        } else if (timer.auto) {
            return ref === "AUTO" ? undefined : "conflict";
        } else if (timer.transition) {
            return ["AUTO", "TELEOP"].includes(ref) ? undefined : "conflict";
        } else if (timer.teleop || timer.endgame) {
            return ref === "TELEOP" ? undefined : "conflict";
        }
    }
}

function getMatchState(activeMatch: HrMatch, timer: MatchTimerData) {
    if (activeMatch.state === "UNPLAYED" || activeMatch.state == "RANDOMIZED") {
        return activeMatch.state === "UNPLAYED" ? t`Unplayed` : t`Randomized`;
    } else if (timer.auto) {
        return 'AUTO';
    } else if (timer.transition) {
        return t`Transition`;
    } else if (timer.teleop || timer.endgame) {
        return 'TELEOP';
    } else {
        return t`Review`;
    }
}

function BigValue({value, alliance}: { value: number; alliance: AllianceColor }) {
    return <div className={`big-value ${alliance.toLowerCase()}`}>
        <div className={`value`}>{value}</div>
    </div>
}

function Live({match}: {match: HrMatch}) {
    const redLock = match.redData.scoringStatus === "SUBMIT" || match.redData.scoringStatus === "REVIEW";
    const blueLock = match.blueData.scoringStatus === "SUBMIT" || match.blueData.scoringStatus === "REVIEW";
    const lock = redLock && blueLock;
    return lock
        ? <span className={"small live frozen"}><i className={"fa fa-snowflake ml-1 mr-1 fa-xs"}/>Display Frozen</span>
        : <span className={"small live"}><i className={"fa fa-circle ml-1 mr-1 fa-2xs"}/>LIVE</span>
}

export default function MatchTab({activeMatch, notes, showNote, send, nowCallback, flip, setFlip, fullscreen, autoOpen, setAutoOpen, dcOpen, setDcOpen, waitForInitSubmit, field, fieldCount, timing} : {
    activeMatch?: HrMatch,
    notes: Record<string, HRMatchNote>,
    showNote: ShowNote,
    send: (message: string) => void,
    nowCallback: () => number,
    flip: boolean,
    setFlip: (flip: boolean) => void,
    fullscreen: boolean,
    autoOpen: number,
    setAutoOpen: (autoOpen: number) => void,
    dcOpen: number,
    setDcOpen: (dcOpen: number) => void,
    waitForInitSubmit: boolean,
    field: number,
    fieldCount: number,
    timing: ParsedMatchTiming
}) {
    const [showCard, setShowCard] = useState(false);
    const [showRP, setShowRPViolations] = useState(false);
    const startAt = activeMatch && activeMatch.start && activeMatch.start > 0 && activeMatch.state !== 'RANDOMIZED' ? activeMatch.start : null;
    const matchTimer = useMatchTimer({ startAt, nowCallback }, timing)
    let timeString = ''
    if(startAt) {
        if (matchTimer.auto) {
            timeString = `(${renderTime(matchTimer.remaining - timing.transition.total('seconds'))})`
        } else if (matchTimer.transition) {
            timeString = `(${renderTime(matchTimer.remaining - timing.teleop.total('seconds'))})`
        } else if (matchTimer.teleop || matchTimer.endgame) {
            timeString = `(${renderTime(matchTimer.remaining)})`
        } else if (matchTimer.done) {
            timeString = `(${renderTime(0)})`
        }
    }

    const initialCards = activeMatch?.isReplay ? {
        RED: [activeMatch.red.scores.oldCard1, activeMatch.red.scores.oldCard2],
        BLUE: [activeMatch.blue.scores.oldCard1, activeMatch.blue.scores.oldCard2],
    } : {
        RED: [0, 0],
        BLUE: [0, 0],
    };
    const replayCards = activeMatch?.isReplay && (initialCards.RED.some(x => x > 0) || initialCards.BLUE.some(x => x > 0));
    const gateSvg = useAsset('img/decode/gate.svg');

    useEffect(() => {
        if (replayCards || activeMatch?.hrCards.RED.some(x => x > 0) || activeMatch?.hrCards.BLUE.some(x => x > 0)) {
            setShowCard(true);
        }
    }, [activeMatch, replayCards])

    useEffect(() => {
        if (replayCards) {
            setReview(true);
        }
    }, [replayCards]);

    const teamNotes = useMemo(() => notesByTeam(notes), [notes]);
    const showTeamNote = (team: number, displayNumber: string, cards: string[]) => showNote(notes, 'teamWithCards', { number: team, displayNumber, cards });


    const Classifier = useCallback(({value}: {value: ArtifactType[]}) => <div className={"text-nowrap"}>
        {[...value].reverse().map((a: ArtifactType, idx: number) => [
            idx % 3 == 0 ? <ReactSVG key={`${idx}-3`} src={idx == 0 ? faSquare : ''} className={"classifier-icon"}></ReactSVG> : null,
            <Artifact value={a} key={`${idx}-2`} matches={activeMatch && randomizationArtifacts[activeMatch.randomization] ? randomizationArtifacts[activeMatch.randomization][2 - (idx % 3)] == a : false} />,
            idx % 3 == 2 ? <><ReactSVG key={`${idx}-3`} src={idx == 8 ? gateSvg : ''} className={"classifier-icon"}></ReactSVG><br/></> : null
        ])}
    </div>, [activeMatch?.randomization])

    if (!activeMatch) {
        return <div id="match" className="tab-pane fade show active alert alert-info text-center" role="tabpanel">{t`No Active Match`}</div>
    }

    const setReview = (r: boolean) => send(JSON.stringify(Object.assign(getUpdateObj(activeMatch), {review: r})));
    const inHrReview = activeMatch.state === "REVIEW" && activeMatch.hrReview &&
        (!window.penaltyTabletEnabled || activeMatch.redData.penaltyStatus === "SUBMIT") && activeMatch.redData.scoringStatus === "SUBMIT" &&
        (!window.penaltyTabletEnabled || activeMatch.blueData.penaltyStatus === "SUBMIT") && activeMatch.blueData.scoringStatus === "SUBMIT"

    const forceReview = (activeMatch: HrMatch, initialCards: Record<AllianceColor, Card[]>) => {
        return JSON.stringify(activeMatch.hrCards.RED) !== JSON.stringify(initialCards.RED) || JSON.stringify(activeMatch.hrCards.BLUE) !== JSON.stringify(initialCards.BLUE);
    }

    const updateFoul = (a: AllianceColor, type: 'Minor' | 'Major', value: number) => {
        const obj = getUpdateObj(activeMatch);
        const lowerAlliance = a.toLowerCase() as 'red' | 'blue';
        obj[`${lowerAlliance}${type}`] = value;
        send(JSON.stringify(obj));
    }

    const toggleAutoOpen: MouseEventHandler<HTMLElement> = (e) => {
        e.preventDefault()
        setAutoOpen(((e.target as HTMLElement).parentElement as HTMLDetailsElement).open ? -1 : 1);
    }
    const toggleDcOpen: MouseEventHandler<HTMLElement> = (e) => {
        e.preventDefault()
        setDcOpen(((e.target as HTMLElement).parentElement as HTMLDetailsElement).open ? -1 : 1);
    }
    const matchState = getMatchState(activeMatch, matchTimer) ;
    const randomizationText = activeMatch.randomization > 0 ? (["", "MOTIF 1 (ID 21)", "MOTIF 2 (ID 22)", "MOTIF 3 (ID 23)"])[activeMatch.randomization] : "-";


    return <div id="match" className="tab-pane fade show active" role="tabpanel">
            <h4 className="text-center">{activeMatch.name}</h4>
            {fieldCount > 1 && field === 0 ? <div className="text-center">{t`Field: ${activeMatch.field}`}</div> : null}
            <div className="text-center">{t`Match Status: ${matchState} ${timeString}`}</div>
            <div className="text-center">{t`Randomization: ${randomizationText}`}</div>
            <div className="text-center hr-artifacts">
                <ReactSVG src={gateSvg} className={"randomizer-icon"}></ReactSVG>
                <Artifact value={activeMatch.randomization > 0 ? randomizationArtifacts[activeMatch.randomization][0] : ArtifactType.NONE} />
                <Artifact value={activeMatch.randomization > 0 ? randomizationArtifacts[activeMatch.randomization][1] : ArtifactType.NONE} />
                <Artifact value={activeMatch.randomization > 0 ? randomizationArtifacts[activeMatch.randomization][2] : ArtifactType.NONE} />
                <ReactSVG src={faSquare} className={"randomizer-icon"}></ReactSVG>
            </div>
            <div style={{display: "flex", justifyContent: "space-between"}}>
                <button className={"btn btn-info"} onClick={() => setFlip(!flip)}>{t`Flip Alliances`}</button>
                <button className={`btn ${activeMatch.hrReview ? "btn-success" : "btn-warning"}`} disabled={inHrReview} onClick={() => setReview(!activeMatch.hrReview || forceReview(activeMatch, initialCards))}>
                    {activeMatch.hrReview ? t`Review Required ` : t`Review Required?`}
                    <i className="fa fa-check" hidden={!activeMatch.hrReview}/>
                </button>
                <button className={"btn btn-info"} onClick={() => showNote(notes?.[activeMatch.shortName] ?? {match: activeMatch.shortName, items: []})}>{t`Add Note`}</button>
            </div>
            {activeMatch.hrReview ?
                inHrReview ? <div className="text-center font-italic alert alert-warning">{t`Scores being held until you submit completion of review.`}</div> :
                    <div className="text-center font-italic">{t`Scores will be held until you submit completion of review`}</div> : null}
            <hr/>

            <ScoreRow activeMatch={activeMatch} flip={flip} label={"Referee Status"} id="statusHeader" component={({alliance}: { alliance: AllianceColor }) => alliance === 'RED' ? t`Red` : t`Blue`} classFn={() => {return {red: "font-weight-bold", middle: "font-weight-bold", blue: "font-weight-bold"}}}/>
            <ScoreRow activeMatch={activeMatch} flip={flip} label={t`Scoring Phase`} component={({alliance}: { alliance: AllianceColor }) => {
                const colorLower = alliance.toLowerCase() as 'red' | 'blue';
                return activeMatch[`${colorLower}Data`].scoringStatus
            }} classFn={() => {
                return {
                    red: getLagStatus(activeMatch.redData.scoringStatus, matchTimer, activeMatch.state, waitForInitSubmit),
                    blue: getLagStatus(activeMatch.blueData.scoringStatus, matchTimer, activeMatch.state, waitForInitSubmit)
                }
            }}/>
            {window.penaltyTabletEnabled ? <ScoreRow activeMatch={activeMatch} flip={flip} label={t`Penalty Phase`} component={({alliance}: { alliance: AllianceColor }) => {
                const colorLower = alliance.toLowerCase() as 'red' | 'blue';
                return activeMatch[`${colorLower}Data`].penaltyStatus
            }} classFn={() => {
                return {
                    red: getLagStatus(activeMatch.redData.penaltyStatus, matchTimer, activeMatch.state, waitForInitSubmit),
                    blue: getLagStatus(activeMatch.blueData.penaltyStatus, matchTimer, activeMatch.state, waitForInitSubmit)
                }
            }}/> : null}
            <ScoreRow activeMatch={activeMatch} flip={flip} label={<>MINOR FOULS<br/><b>{t`Total`}</b></>} fieldName={"minor"} component={BigValue} />
            <ScoreRow activeMatch={activeMatch} flip={flip} label={<>Foul input: R / B</>} fieldName={{
                RED: ["ownMinorFouls", "otherMinorFouls"],
                BLUE: ["otherMinorFouls", "ownMinorFouls"]
            }}/>
        <ScoreRow activeMatch={activeMatch} flip={flip} label={<><div>{t`HR MINOR FOULS`}</div><Live match={activeMatch}/></>} fieldName={"hrMinorFouls"} component={({value, alliance}: {value: number, alliance: AllianceColor}) =>
                <Counter color={alliance} value={value} plain setValue={(val) => updateFoul(alliance, 'Minor', val)} />} />
            <ScoreRow activeMatch={activeMatch} flip={flip} label={<>MAJOR FOULS<br/><b>{t`Total`}</b></>} fieldName={"major"} component={BigValue} />
            <ScoreRow activeMatch={activeMatch} flip={flip} label={<>Foul input: R / B</>} fieldName={{
                RED: ["ownMajorFouls", "otherMajorFouls"],
                BLUE: [ "otherMajorFouls", "ownMajorFouls"]
            }}/>
        <ScoreRow activeMatch={activeMatch} flip={flip} label={<><div>{t`HR MAJOR FOULS`}</div><Live match={activeMatch}/></>} fieldName={"hrMajorFouls"} component={({value, alliance}: {value: number, alliance: AllianceColor}) =>
                <Counter color={alliance} value={value} plain setValue={(val) => updateFoul(alliance, 'Major', val)} />} />
            <hr/>

            <details className={"scores autoScores"} open={(fullscreen && (autoOpen === 0)) || (autoOpen === 1)}>
                <summary className="btn btn-secondary btn-sm col-12" onClick={toggleAutoOpen}>{t`AUTO Scores`}</summary>
                <ScoreRow activeMatch={activeMatch} flip={flip} label={t`CLASSIFIED`} fieldName={"autoClassifiedArtifacts"} component={Positive} />
                <ScoreRow activeMatch={activeMatch} flip={flip} label={t`OVERFLOW`} fieldName={"autoOverflowArtifacts"} component={Positive} />
                <ScoreRow activeMatch={activeMatch} flip={flip} label={t`PATTERN`} fieldName={"autoClassifierState"} component={Classifier} />
                <ScoreRow activeMatch={activeMatch} flip={flip} label={t`ROBOT Location`} fieldName={["robot1Auto", "robot2Auto"]} component={Check}/>
            </details>
            <details className={"scores"} open={(fullscreen && (dcOpen === 0)) || (dcOpen === 1)}>
                <summary className="btn btn-secondary btn-sm col-12" onClick={toggleDcOpen}>{t`TELEOP Scores`}</summary>
                <ScoreRow activeMatch={activeMatch} flip={flip} label={t`CLASSIFIED`} fieldName={"teleopClassifiedArtifacts"} component={Positive} />
                <ScoreRow activeMatch={activeMatch} flip={flip} label={t`OVERFLOW`} fieldName={"teleopOverflowArtifacts"} component={Positive} />
                <ScoreRow activeMatch={activeMatch} flip={flip} label={t`DEPOT`} fieldName={"teleopDepotArtifacts"} component={Positive} />
                <ScoreRow activeMatch={activeMatch} flip={flip} label={t`PATTERN`} fieldName={"teleopClassifierState"} component={Classifier} />
                <ScoreRow activeMatch={activeMatch} flip={flip} label={t`ROBOT Location`} fieldName={["robot1Teleop", "robot2Teleop"]} component={RobotLocation}/>
            </details>
            <hr/>

            {activeMatch && activeMatch.type != MatchType.ELIMS ? <>
                <h6 className={"text-center"}>{t`RP Violations`}</h6>
                {showRP ?<>
                    <div className={"d-flex justify-content-between"} style={{position: 'relative'}}>
                        <AllianceRpInputs activeMatch={activeMatch} alliance={flip ? AllianceColor.RED : AllianceColor.BLUE} send={send}/>
                        <AllianceRpInputs activeMatch={activeMatch} alliance={flip ? AllianceColor.BLUE : AllianceColor.RED} send={send}/>
                    </div>
                    <div className={"text-center"}><button className={"btn btn-info btn-sm"} onClick={() => setShowRPViolations(false)} disabled={activeMatch.hrViolations[AllianceColor.BLUE].length > 0 || activeMatch.hrViolations[AllianceColor.RED].length > 0}>Hide RP Violations</button></div>
                    </>
                :
                    <div className={"text-center"}><button className={"btn btn-info btn-sm"} onClick={() => setShowRPViolations(true)}>Enter RP Violations</button></div>
                }
            <hr/>
            </>:null}

            <h6 className={"text-center"}>{t`Teams / Cards`}</h6>
            <div style={{position: 'relative'}}>
                {showCard ? null : <div className={'text-center'} style={{position: 'absolute', top: '1.5em', left: 0, right: 0, marginLeft: 'auto', marginRight: 'auto', zIndex: 5, width: 'fit-content'}}><button className={"btn btn-info btn-sm"} onClick={() => setShowCard(true)}>Assign Cards</button></div>}
                <CardRow activeMatch={activeMatch} flip={flip} robot={1} send={send} showCard={showCard} notes={teamNotes} showNote={showTeamNote} initialCards={initialCards}/>
                <CardRow activeMatch={activeMatch} flip={flip} robot={2} send={send} showCard={showCard} notes={teamNotes} showNote={showTeamNote} initialCards={initialCards}/>
                <CardRow activeMatch={activeMatch} flip={flip} robot={3} send={send} showCard={showCard} notes={teamNotes} showNote={showTeamNote} initialCards={initialCards}/>
                {replayCards ? <div className={"text-center font-italic"}>{t`This is a replay - cards earned in this match have been restored. Enter an additional YC as a 2nd YC.`}</div> : null}
                {showCard ? <div className={'text-center'} style={{paddingTop:'5px'}}><button className={"btn btn-info btn-sm"} onClick={() => setShowCard(false)} disabled={activeMatch.hrCards.RED.some(x => x > 0) || activeMatch.hrCards.BLUE.some(x => x > 0)}>Hide Cards</button></div> : null}
            </div>
{
    inHrReview ? <><br/>
        <div className="text-center">
            <button className={"btn btn-primary"} onClick={() => {
                const obj = getUpdateObj(activeMatch);
                obj.type = 'SUBMIT';
                send(JSON.stringify(obj));
            }}>{t`Submit Review`}</button>
        </div>
    </> : null
}

</div>

}
