export type SeasonScores = DecodeScores

interface FullTeamInfo {
    data: HRTeamInfo
    // Other data HR doesn't need
}

export interface Alliance<T extends Scores> {
    team1: FullTeamInfo,
    team2: FullTeamInfo,
    team3?: FullTeamInfo,
    robot1: number,
    robot2: number,
    team1Surrogate: boolean,
    team2Surrogate: boolean,
    scores : T,
    seed?: number
}

interface HRTeamInfo {
    number: number,
    displayNumber: string,
    cards?: string[]
}

export enum RefStatus {
    INIT = 'INIT',
    READY = 'READY',
    AUTO = 'AUTO',
    TELEOP = 'TELEOP',
    REVIEW = 'REVIEW',
    SUBMIT = 'SUBMIT',
}

interface HrAllianceData {
    cc1: string[],
    cc2: string[],
    scoringStatus: RefStatus,
    penaltyStatus: RefStatus,
}

export interface HrMatch extends Match {
    red: Alliance<SeasonScores>,
    blue: Alliance<SeasonScores>,
    redData: HrAllianceData,
    blueData: HrAllianceData,
}

export interface HrBasicMatch {
    number: number,
    field: number,
    start?: number,
    state: MatchState,
    name: string,
    shortName: string,
    type: MatchType,
    red: HRTeamInfo[],
    blue: HRTeamInfo[],
    redSeed?: number,
    blueSeed?: number,
    round?: number,
    redSeedString?: string,
    blueSeedString?: string
}

export interface TeamNote {
    content: string,
    match: string,
    others: number[]
}

export type ShowNote = {
    (noteList: HRMatchNote): void
    (noteList: HRMatchNote, type: 'match'): void
    (noteList: Record<string, HRMatchNote>, type: 'team', team: HRTeamInfo): void
    (noteList: Record<string, HRMatchNote>, type: 'teamWithCards', team: HRTeamInfo & { cards: string[] }): void
}

export function getMatchFromShortName(matchList: HrBasicMatch[], shortName: string) {
    return matchList.find(x => x.shortName === shortName);
}

export function isRunning(state: MatchState) {
    return state === "AUTO" || state === "TELEOP";
}

// TODO type better
function matchReducer(current: HrMatch | undefined, data: any, send: (data: string) => void, field: number) {
    if(current && data.type === "CANCEL" && data.matchNum === current.number) {
        return undefined;
    }
    // return the new activeMatch state
    if (!data.match) {
        return current; // ignore this message
    }
    let newState = Object.assign({}, current);
    if (field === 0 || data.match.field === field || data.match.field === 0) {
        // replace with new match object if there isn't a current one, the current one is for the same match, or the current one is a different match that is not running &&  not in hrReview
        if (!current || current.shortName === data.match.shortName || (!isRunning(current.state) && !current.hrReview)) {
            if (current?.state === 'REVIEW' && current.shortName !== data.match.shortName && !isRunning(data.match)) {
                // if still in (alliance ref) review & HR Review is unchecked, dont swap unless the next match starts
                // TODO this will still swap on start, do we want a popup for this scenario where the user can choose to ignore updates from the next match until submit?
            } else {
                newState = data.match;
            }
        }
        // else ignore because another match is active
    }
    /*
    Previous version had this block here, figure out once needed: (needed for c08 "next match" logic)
    if (data.type === "START" || data.type === "RANDOMIZE") {
        if (data.type === "START" && matchList) {
            let m = matchList.find(x => x.number = data.match.number);
            if (m) {
                m.start = data.match.start;
            }
        }
        resetC08Timer(data.match);
    }
     */
    // Only request data if this is an HR page on the correct division
    if (data.division === window.division && newState && newState.state === "SUBMITTED") {
        // wait 2s so it's obvious a new match is loading.
        if (current != null) {
            setTimeout(() => send(JSON.stringify({type: "FETCH", field: field, first: false})), 2000);
        }
        return undefined;
    }
    return Object.keys(newState).length > 0 ? newState : current;
}

function TimeoutTimer({start, duration, label, type, nowCallback}: {
    start?: number,
    duration?: number,
    label: string,
    type?: string,
    nowCallback: () => number
}) {
    const EMPTY = <div className={"col-2"}/>;
    const timer = useTimer({
        startAt: start,
        duration: duration ? (duration / 1000) : 0,
        nowCallback: nowCallback
    });
    if (!start || !duration) {
        return EMPTY;
    }
    if (start === 0 || (!timer.running && timer.remaining > 0)) {
        return EMPTY;
    }
    return <div className={`col-2 text-sm-center ${start > 0 ? (type === 'ELIMS_TIMEOUT' && timer.remaining <= 240 ? "alert-danger": "alert-warning") : null} c08Timer`}>
        <span>{label}</span><br/><span>{renderTime(timer.remaining)}</span>
    </div>
}

declare global {
    function showHrHelp(): void;
}

interface HrData {
    matchList: HrBasicMatch[],
    activeMatch?: HrMatch,
    notes: Record<string, HRMatchNote>,
    meetingNotes: Partial<Record<HrMeetingNoteType, string>>,
    timeouts: TimeoutReference[],
    nextMatch?: HrMatch,
    g301Start: number,
    waitForInitSubmit: boolean,
    requestEhr: boolean,
    refCounts: Map<RefereePosition, Record<string, number>>
}

const defaultHrData: HrData = {
    matchList: [],
    activeMatch: undefined,
    notes: {},
    meetingNotes: {},
    timeouts: [],
    nextMatch: undefined,
    g301Start: 0,
    waitForInitSubmit: false,
    requestEhr: false,
    refCounts: new Map()
}

type RefCountUpdate = {position: RefereePosition, byField: Record<string, number>};

function updateHrData(current: Record<number, HrData>, action: any, send: (data: string) => void, field: number) {
    const division = action.division;
    const currentData = current[division] ? {...current[division]} : {...defaultHrData};

    if (action.type === "MATCH_LIST") {
        currentData.matchList = action.list;
    } else if (action.type === "NOTES") {
        currentData.notes = action.notes;
        currentData.meetingNotes = action.meetings;
    } else if (action.type === "TIMEOUTS") {
        currentData.g301Start = action.g301Timer;
        currentData.timeouts = action.timeouts;
        currentData.nextMatch = action.nextMatch;
    } else if (["LOAD", "INIT", "START", "SCORE", "REVIEW", "ABORT", "RANDOMIZE", "FETCH", "LOCKOUT", "SUBMIT", "CANCEL"].includes(action.type)) {
        currentData.activeMatch = matchReducer(currentData.activeMatch, action, send, field);
        if((action.type === "START" || action.type === "ABORT") && action.match) {
            currentData.matchList = currentData.matchList.map(m => {
                if (m.shortName === action.match.shortName) {
                    return {...m, start: action.match.start};
                }
                return m;
            })
        }
    } else if (action.type === "WAIT_FOR_INIT_SUBMIT") {
        currentData.waitForInitSubmit = action.waitForInitSubmit;
    } else if (action.type === "EHR_CONFIG") {
        currentData.requestEhr = action.requestEhr;
    } else if (action.type === "PARTIAL_REF_COUNTS") {
        currentData.refCounts.set(action.position, action.byField);
    } else if (action.type === "FULL_REF_COUNTS") {
        currentData.refCounts = new Map(action.counts.map((c : RefCountUpdate) => [c.position, c.byField]));
    } else {
        console.log("Unknown message type " + action.type);
    }

    return {
        ...current,
        [division]: currentData
    }
}

export default function HeadRef({field, fieldCount, event, hrControl, timing, eventType}: {
    field: number,
    fieldCount: number,
    event: string,
    hrControl: string,
    timing: ParsedMatchTiming,
    eventType: string
}) {
    const { isConnected, now: nowCallback, send } = usePersistentWebsocketWithTime(
        `/stream/hr/?code=${event}&field=${field}`,
        handleMessage,
        (socket) => {
            socket.send(JSON.stringify({type: "FETCH", field: field, first: true}));
        });
    const [tab, setTab] = useState<string | undefined>('match');
    // TODO type the reducer args
    const [data, dispatchUpdate] = useReducer((current: Record<number, HrData>, data: any) => updateHrData(current, data, send, field), {})
    const [flip, setFlip] = useLocalStorageState<boolean>('hrFlip');
    const [autoOpen, setAutoOpen] = useLocalStorageState<number>('hrAutoOpen', 0);
    const [dcOpen, setDcOpen] = useLocalStorageState<number>('hrDcOpen', 0);
    const [noteOpen, setNoteOpen] = useState(false);
    const [currentNote, setCurrentNote] = useState<HRMatchNote>();
    const [noteMode, setNodeMode] = useState('match');
    const [currentTeamNotes, setCurrentTeamNotes] = useState<{team: HRTeamInfo, notes: TeamNote[]}>();
    const fullscreen = useFullscreenState();

    const divisionData = data[window.division] || defaultHrData;
    const {matchList, activeMatch, notes, meetingNotes, timeouts, nextMatch, g301Start, waitForInitSubmit, requestEhr, refCounts} = divisionData;

    // TODO type this better
    function handleMessage(msg: any) {
        // Remember, this function is within the closure, so does not have updated state!
        if (msg.match) { // rescope the alliance data for later convenience
            msg.match.redData = msg.redData;
            msg.match.blueData = msg.blueData;
        }
        dispatchUpdate(msg);
    }

    const showNote: ShowNote = (noteData, type: 'match' | 'team' | 'teamWithCards' = 'match', teamData = {}) => {
        setNodeMode(type);
        if (type === 'match') {
            setCurrentNote(noteData as HRMatchNote)
        } else if (type === 'team' || type === 'teamWithCards') {
            const obj: { team: HRTeamInfo, notes: TeamNote[] } = {team: teamData as HRTeamInfo, notes: []}
            for (let k in noteData) {
                (noteData as Record<string, HRMatchNote>)[k].items.filter(x => x.tags.includes(obj.team.number)).forEach(x => obj.notes.push({match: k, content: x.content, others: x.tags.filter((i) => i !== obj.team.number)}));
            }
            setCurrentTeamNotes(obj);
        }
        setNoteOpen(true);
    }

    const requestEventHr = async () => {
        const msg = await promptDialog({label: "Request Event HR", text: "Message to EHR:", buttonText: "Request", defaultValue: ""});
        if (msg !== null) {
            fetch('./request/', {method: 'POST', body: msg})
        }
    }

    // iterate over every position and check for conflicts on same number or 0 + any number. If this HR page is bound, only check for conflicts on that number and that # + 0.
    interface Conflict {pos: RefereePosition, counts: Record<string, number>}
    const conflicts: Conflict[] = [];
    [RefereePosition.SCORING_RED, RefereePosition.SCORING_BLUE, RefereePosition.PENALTY_RED, RefereePosition.PENALTY_BLUE].map(pos => {
        const counts = refCounts.get(pos);
        if (!counts) return;
        if (field !== 0) {
            // only check for conflicts on field & field + 0
            const i = field + "";
            if ((counts[i] ?? 0) + (counts["0"] ?? 0) > 1) {
                conflicts.push({pos: pos, counts: {0: counts["0"], [i]: counts[i]}});
            }
        } else {
            // check all conflicts. 0 conflicts with any, non-0 conflicts with itself
            const entries = Object.entries(counts);
            if ((counts["0"] ?? 0) > 0 && entries.filter(([k,v]) => k !== "0").map(([k, v]) => v).reduce((p,c) => p+c, 0) > 0) {
                conflicts.push({pos: pos, counts: Object.fromEntries(entries.filter(([k, v]) => v > 0))});
            } else {
                entries.filter(([k,v]) => v > 1).forEach(([k,v]) => conflicts.push({pos: pos, counts: {[k]: v}}))
            }
        }
    });

    return <>
        <NoteDialog show={noteOpen && noteMode === 'match'} setShow={setNoteOpen} note={currentNote} setNote={setCurrentNote} send={send}
                    match={currentNote ? getMatchFromShortName(matchList, currentNote.match) : undefined}/>
        <TeamNotesDialog show={noteOpen && (noteMode === 'team' || noteMode === 'teamWithCards')} setShow={setNoteOpen} notes={currentTeamNotes} noteList={notes} showNote={showNote} send={send}
                    matchList={matchList.filter(x => [...x.red, ...x.blue].filter(x => x).map(x => x.number).includes(currentTeamNotes?.team?.number || -1))} />
        <div className="row">
            <a href={`/event/${event}/`} className="col-4 text-left">{t`<< Back`}</a>
            <a href="#" className={"col-4 text-center"} onClick={() => toggleFullscreen()}>{fullscreen ? "Exit Fullscreen" : "Fullscreen"}</a>
            <a href="#" className="col-4 text-right" onClick={() => showHrHelp()}>{t`Help`}</a>
        </div>
        <div className="row justify-content-center">
            <h2 className="col-8 text-center offset-2">{t`Head Referee`} {fieldCount > 1 ? `(${field == 0 ? t`All Fields` : t`Field ${field}`})` : ''}</h2>
            <div className="col-2 text-right"><Button size={"sm"} hidden={!requestEhr} onClick={e => requestEventHr()}>Request EHR</Button></div>
        </div>
        { isConnected ? null : <div className={"alert alert-danger text-center h6"}>{t`DISCONNECTED`}</div>}
        { conflicts.length ? <div className={"alert alert-warning text-center"}>
            <i className={"fa fa-exclamation-triangle"}/> {t`WARNING! There are multiple referees in the same position!`}<i className={"fa fa-exclamation-triangle ml-1"}/>
            {conflicts.map(c => <div key={c.pos}>{c.pos.replaceAll("_", " ")}: {Object.entries(c.counts).filter(([f, r]) => r > 0).map(([f, r]) => <span key={f} className={"mr-1 ml-1"}>({r} on {f === "0" ? "any field" : "field " + f})</span> )}</div>)}
        </div> : null }
        <LocalErrorBoundary>
            <Tabs defaultActiveKey={"match"} activeKey={tab} onSelect={(v) => v ? setTab(v) : setTab(undefined)} unmountOnExit={false}>
                <Tab eventKey={"match"} title={"Active Match"}>
                    <MatchTab activeMatch={activeMatch} notes={notes} showNote={showNote} send={send} nowCallback={nowCallback} timing={timing}
                              flip={flip} setFlip={setFlip} fullscreen={fullscreen} autoOpen={autoOpen} setAutoOpen={setAutoOpen}
                              dcOpen={dcOpen} setDcOpen={setDcOpen} waitForInitSubmit={waitForInitSubmit} fieldCount={fieldCount} field={field} />
                </Tab>
                {hrControl !== undefined && hrControl.length > 0 ?
                    <Tab eventKey={"control"} title={<div title={field !== 0 ? "Not available on field-bound HR page." : ""} style={{pointerEvents: 'auto'}}>Match Control</div>}>
                    <HrControlTab controlSettings={hrControl} eventCode={event} timing={timing} field={field} eventType={eventType} showMatchTab={() => {
                        setTab('match');
                    }}/>
                </Tab> : null}
                <Tab eventKey={"notes"} title={"Notes"}>
                    <NotesTab notes={notes} meetingNotes={meetingNotes} matchList={matchList} send={send} showNote={showNote} />
                </Tab>
                <Tab eventKey={"timing"} title={"Timers"}>
                    {!window.isParent || matchList.length > 0
                        ? <TimingTab activeMatch={activeMatch} matchList={matchList} timeouts={timeouts} nextMatch={nextMatch} send={send} nowCallback={nowCallback} field={field} eventType={eventType} timing={timing}/>
                        : <MultiDivisionTimingTab divisionTimeoutData={data} divisionNames={window.divisions!} nowCallback={nowCallback} isHr={true}/>
                    }
                </Tab>
                <Tab eventKey={"scores"} title={"Scoresheets"}>
                    <ScoresheetTab matchLists={Object.fromEntries(Object.entries(data).map(([k, v]) => [k, v.matchList]))} divisionNames={window.divisions}/>
                </Tab>
            </Tabs>
        </LocalErrorBoundary>
    </>
}