import HeadRef from "./HeadRef";
import LocalErrorBoundary from "../LocalErrorBoundary";
import { createRoot } from "react-dom/client";
import {parseMatchTiming} from "ftc-common/utils";
import {MatchTiming} from "ftc-common/javaTypes";
declare global {
    interface Window {
        field: number
        fieldCount: number
        eventCode: string
        hrControl: string
        isDivision: boolean
        isParent: boolean
        division: number
        divisions?: string[]
        penaltyTabletEnabled: boolean
        matchTiming: MatchTiming
        eventType: string
    }
}

const container = document.getElementById('headRefContent');
if (!container) {
    console.error("Mount point for head ref container not found")
} else {
    const root = createRoot(container);
    root.render(<LocalErrorBoundary>
        <HeadRef field={window.field} event={window.eventCode} fieldCount={window.fieldCount} hrControl={window.hrControl} timing={parseMatchTiming(window.matchTiming)} eventType={window.eventType} />
    </LocalErrorBoundary>);
}
