import './NotesTab.css';
import {useState} from "react";
import ReactQuill from "react-quill";
import 'react-quill/dist/quill.snow.css';
import { HRMatchNote } from "../javaTypes";
import { HrMeetingNoteType } from "ftc-common/javaTypes";
import { t } from "ftc-common/i18n";
import { HrBasicMatch, ShowNote, TeamNote } from "./HeadRef";

function MatchView({notes, matchList, showNote}: {
    notes: Record<string, HRMatchNote>,
    matchList: HrBasicMatch[],
    showNote: ShowNote
}) {
    const getOneLiner = (note: HRMatchNote) => {
        /* Returns what to show in the match notes table - if summary exists, show that. Else show either the note or the number of notes */
        if (note.summary && note.summary.length > 0) {
            return note.summary
        }
        /* If only one item and no summary, show that item */
        if (note.items.length === 1) {
            const tags = note.items[0].tags.length > 0 ? '[' + note.items[0].tags.join(", ") + '] ' : '';
            return tags + note.items[0].content;
        } else if (note.items.length > 1) {
            return '[' + note.items.length + ' notes]';
        }
        return '';
    }
    const fullMatchList: (HrBasicMatch | { shortName: string, fake: true })[] = [...matchList];
    // reverse the sort so that inserting at the front is correct for the missing matches
    for (const matchNote of Object.values(notes).sort((a,b) => -matchSortShortname(a.match, b.match))) {
        if (matchNote.match === 'G') {
            continue;
        }
        if (fullMatchList.filter(x => matchNote.match === x.shortName).length === 0) {
            // We don't have the match that this note belongs to - fake it
            fullMatchList.splice(0, 0, {'shortName': matchNote.match, 'fake': true})
        }
    }
    const rows = fullMatchList.map(match => <tr key={match.shortName} onClick={() => showNote(notes?.[match.shortName] ?? {match: match.shortName, items: []})}>
        <th>{match.shortName}</th>
        <td>{notes[match.shortName] ? getOneLiner(notes[match.shortName]) : null}</td>
    </tr>);

    return <>
        <div className="text-center">{t`Tap on a row to open the notes for that match.`}</div>
        <table id="notesTable" className="table">
            <thead>
                <tr id="notesHeader"><th>{t`Match`}</th><th>{t`Notes`}</th></tr>
            </thead>
            <tbody>
                {rows}
            </tbody>
        </table>
    </>;
}

/**
 * Modified from the one in FTA Notepad to accommodate the 'G'
 */
function matchSortShortname(a: string, b: string) {
    const a_last_space = a.lastIndexOf(' ');
    let orig_a_part = '';
    if (a_last_space > -1) {
        orig_a_part = a.substring(0, a_last_space);
        a = a.substring(a_last_space + 1);
    }
    const b_last_space = b.lastIndexOf(' ');
    let orig_b_part = '';
    if (b_last_space > -1) {
        orig_b_part = b.substring(0, b_last_space);
        b = b.substring(b_last_space + 1);
    }
    const sfNum = (m: string) => (m[2] === "1" ? 1 : 2) + parseInt(m.substring(4));
    if (orig_a_part.length > 0 && orig_a_part !== orig_b_part) {
        return orig_a_part.localeCompare(orig_b_part);
    }
    if (a[0] === b[0]) {
        return a[0] === 'S' ? sfNum(a) - sfNum(b) : (parseInt(a.substring(1)) - parseInt(b.substring(1)));
    } else {
        const toLevel = (m: string) => m[0] === 'G' ? -1 : (m[0] === 'Q' ? 0 : (m[0] === 'S' ? 1 : 2));
        return toLevel(a) - toLevel(b);
    }
}

export function notesByTeam(notes: Record<string, HRMatchNote>) {
    /*
     * Notes are keyed by match. Need the note items extracted and keyed by tagged team
     */
    const teamMap = new Map<number, TeamNote[]>();
    // Order not guaranteed here! Need to re-sort.
    for (let note of Object.values(notes).sort((a,b) => matchSortShortname(a.match, b.match))) {
        for (let item of note.items) {
            for (let team of item.tags) {
                const noteSummary = (note.hasOwnProperty('summary') ? note.summary : '');
                const itemContent = (item.hasOwnProperty('content') ? item.content : '');
                // If we have both a noteSummary and itemContent, put a separator between them
                const separator = (noteSummary?.length ?? 0) > 0 && (itemContent?.length ?? 0) > 0 ? '; ' : '';
                const contentToShow = noteSummary + separator + itemContent;
                teamMap.set(team, [...(teamMap.get(team) ?? []), {match: note.match, content: contentToShow, others: item.tags.filter(x => x !== team)}]);
            }
        }
    }
    return teamMap
}


function TeamView({notes, matchList, showNote}: {
    notes: Record<string, HRMatchNote>,
    matchList: HrBasicMatch[],
    showNote: ShowNote
}) {
    const teamMap = notesByTeam(notes);
    let seedMap = new Map<number, number>();
    let stringSeedMap = new Map<number, string>();
    if(window.isParent) {
        seedMap = matchList.flatMap(x => [...x.red.map(t => ({number: t.number, seed: x.redSeed})), ...x.blue.map(t => ({number: t.number, seed: x.blueSeed}))])
            .filter((x): x is { number: number, seed: number } => !!x.seed)
            .reduce((map, obj) => map.set(obj.number, obj.seed), new Map<number, number>());
        stringSeedMap = matchList.flatMap(x => [...x.red.map(t => ({number: t.number, seed: x.redSeedString})), ...x.blue.map(t => ({number: t.number, seed: x.blueSeedString}))])
            .filter((x): x is { number: number, seed: string } => !!x.seed)
            .reduce((map, obj) => map.set(obj.number, obj.seed), new Map<number, string>());
    }
    // Round-trip through JSON to uniquify objects
    const teams = [... new Set(matchList.flatMap(x => [...x.red, ...x.blue].map(x => JSON.stringify(x))))]
        .map(x => JSON.parse(x)).filter(x => x && x.number > 0)
        .sort((a,b) => {
            const aSeed = seedMap.get(a.number);
            const bSeed = seedMap.get(b.number);
            if (aSeed !== undefined && bSeed !== undefined && aSeed !== bSeed) {
                return aSeed - bSeed;
            }
            return a.number - b.number
        });


    const renderTeamRowContent = (notes: TeamNote[]) => {
        return notes.length === 0 ? "" : notes.map((x, idx) => <div key={idx}>{`${x.match}: ${x.content}`}</div>);
    }
    const rows = teams.map(team => <tr key={team.number} onClick={() => showNote(notes, 'team', team)}>
        <th>{window.isParent ? <>{stringSeedMap.get(team.number) ?? ''} </> : null} {team.displayNumber}</th>
        <td>{renderTeamRowContent(teamMap.get(team.number) ?? [])}</td>
    </tr>);
    return <>
        <div className="text-center">{t`Tap on a row to open the notes for that team.`}</div>
        <table id="notesTable" className="table">
            <thead>
                <tr id="notesHeader"><th>{t`Team`}</th><th>{t`Notes`}</th></tr>
            </thead>
            <tbody>
                {rows}
            </tbody>
        </table>
    </>;
}

function MeetingNote({type, note, setNote, meetingNotes, send}: {
    type: HrMeetingNoteType,
    note: string,
    setNote: (note: string) => void,
    meetingNotes: Partial<Record<HrMeetingNoteType, string>>,
    // TODO: eventually type this
    send: (message: string) => void
}) {
    const [editing, setEditing] = useState(false);
    const meetingInfo = MEETINGS.find(x => x.type === type);
    if(!meetingInfo) {
        console.error(`Could not find meeting of type ${type}`)
        return <>An error occurred</>
    }
    const label = meetingInfo.label;

    // TODO have a page in cloud to enter the default text
    return <>
        <h4 className={"text-center"}>{t`${label} Meeting Notes`}</h4>
        {editing ? <ReactQuill theme="snow" value={note ?? ""} onChange={(content) => {
            setNote(content);
        }} />: <div dangerouslySetInnerHTML={{__html: note}} /> }
        <div className={"d-flex justify-content-end meetingEditBtns"}>
            <button className={"btn btn-secondary"} hidden={!editing} onClick={() => {
                setNote(meetingNotes[type] || '');
                setEditing(false);
            }}>{t`Discard`}</button>
            <button className={"btn btn-primary"} hidden={editing} onClick={() => setEditing(true)}> {t`Edit`}</button>
            <button className={"btn btn-primary"} hidden={!editing} onClick={() => {
                send(JSON.stringify({type: "MEETING_NOTE", meeting: type, content: note }));
                setEditing(false);
            }}> {t`Save`}</button>
        </div>
    </>
}

const MEETINGS = [{type: HrMeetingNoteType.REFEREE, label: t`Referee`}, {type: HrMeetingNoteType.DRIVER, label: t`Drivers`}, {type: HrMeetingNoteType.CAPTAIN, label: t`Captains`}, {type: HrMeetingNoteType.OTHER, label: t`Other`}];

export default function NotesTab({notes, meetingNotes, matchList, send, showNote}: {
    notes: Record<string, HRMatchNote>,
    meetingNotes: Partial<Record<HrMeetingNoteType, string>>,
    matchList: HrBasicMatch[],
    // TODO: eventually type this
    send: (message: string) => void,
    showNote: ShowNote
}) {
    // TODO render rule references once we distribute pdf viewer - cold also have a "Manuals" tab with pdfjs embedded that render the manual

    const [subTab, setSubTab] = useState('match');
    const [meeting, setMeeting] = useState(HrMeetingNoteType.REFEREE);
    const [meetingNote, setMeetingNote] = useState('');

    let content = null;
    if (subTab === 'match') {
        content = <MatchView notes={notes} matchList={matchList} showNote={showNote}/>;
    } else if (subTab === 'team') {
        content = <TeamView notes={notes} matchList={matchList} showNote={showNote}/>;
    } else if (subTab === "meeting") {
        content = <MeetingNote type={meeting} note={meetingNote} setNote={setMeetingNote} meetingNotes={meetingNotes} send={send}/>
    }

    const showMeetingNote = (type: HrMeetingNoteType) => {
        setMeetingNote(meetingNotes[type] || '');
        setSubTab(`meeting`);
        setMeeting(type);
    }
    const dropdowns = MEETINGS.map(m => <a key={m.type} className={`dropdown-item ${subTab === `meeting_${m.type}` ? 'current' : null}`} href="#" onClick={() => showMeetingNote(m.type)}>{m.label}</a>);

    return <div id="notes" className="tab-pane fade show" role="tabpanel">
        <div className={"d-flex justify-content-center noteSelectBtns"} style={{padding: '10px'}}>
            <button className={`btn ${subTab === 'match' ? 'btn-outline-secondary' : 'btn-secondary'}`} onClick={() => setSubTab('match')}>{t`By Match`}</button>
            <button className={`btn ${subTab === 'team' ? 'btn-outline-secondary' : 'btn-secondary'}`} onClick={() => setSubTab('team')}>{t`By Team`}</button>
            <div className={"dropdown"}>
                <button id={"meetingDropdown"} className={`btn btn-secondary dropdown-toggle`} data-toggle="dropdown" aria-haspopup="true">{t`Meeting`}</button>
                <div className="dropdown-menu" aria-labelledby="meetingDropdown"> {dropdowns} </div>
            </div>
        </div>
        {content}
    </div>
}